// Calculate date range: today and 4 weeks ago
const now = new Date();
const today = now.toISOString().split('T')[0];

const fourWeeksAgo = new Date(now.getTime() - 28 * 24 * 60 * 60 * 1000);
const fourWeeksAgoStr = fourWeeksAgo.toISOString().split('T')[0];

return [{ json: {
  today,
  fourWeeksAgoStr,
  nowIso: now.toISOString()
} }];

// Compare today's metrics to 4-week rolling average
// Skip metrics with <7 days history or avg=0
const todayResponse = $('Fetch Today Metrics').first().json;
const historyResponse = $('Fetch 4-Week History').first().json;

const todayMetrics = todayResponse.body || todayResponse || [];
const historyMetrics = historyResponse.body || historyResponse || [];

if (!Array.isArray(todayMetrics) || todayMetrics.length === 0) {
  return [{ json: { anomalies: [], status: 'no_today_data' } }];
}

// Group history by metric_name
const historyByMetric = {};
if (Array.isArray(historyMetrics)) {
  for (const row of historyMetrics) {
    const name = row.metric_name;
    if (!historyByMetric[name]) historyByMetric[name] = [];
    historyByMetric[name].push(parseFloat(row.metric_value) || 0);
  }
}

const anomalies = [];

for (const metric of todayMetrics) {
  const name = metric.metric_name;
  const todayValue = parseFloat(metric.metric_value) || 0;
  const history = historyByMetric[name] || [];

  // Skip if fewer than 7 data points
  if (history.length < 7) continue;

  const avg = history.reduce((s, v) => s + v, 0) / history.length;

  // Skip if average is 0 (avoid division by zero, metric not meaningful)
  if (avg === 0) continue;

  const deviation = ((todayValue - avg) / Math.abs(avg)) * 100;
  const absDeviation = Math.abs(deviation);

  if (absDeviation > 25) {
    const severity = absDeviation > 50 ? 'critical' : 'warning';
    const direction = deviation > 0 ? 'above' : 'below';
    anomalies.push({
      metric_name: name,
      today_value: todayValue,
      avg_value: Math.round(avg * 100) / 100,
      deviation_pct: Math.round(deviation * 100) / 100,
      direction,
      severity,
      data_points: history.length
    });
  }
}

// Sort: critical first, then by absolute deviation
anomalies.sort((a, b) => {
  if (a.severity !== b.severity) return a.severity === 'critical' ? -1 : 1;
  return Math.abs(b.deviation_pct) - Math.abs(a.deviation_pct);
});

return [{ json: { anomalies, count: anomalies.length, status: anomalies.length > 0 ? 'anomalies_found' : 'all_normal' } }];

// Build HTML alert table for anomalies
const { anomalies } = $json;
const timestamp = new Date().toLocaleString('en-US', { timeZone: 'America/Chicago' });

const rows = anomalies.map(a => {
  const color = a.severity === 'critical' ? '#dc2626' : '#ea580c';
  const arrow = a.direction === 'above' ? '&#9650;' : '&#9660;';
  const sign = a.deviation_pct > 0 ? '+' : '';
  return `<tr>
    <td style="padding: 8px 12px; border-bottom: 1px solid #e5e7eb;">${a.metric_name.replace(/_/g, ' ')}</td>
    <td style="padding: 8px 12px; border-bottom: 1px solid #e5e7eb; text-align: right;">${a.today_value}</td>
    <td style="padding: 8px 12px; border-bottom: 1px solid #e5e7eb; text-align: right;">${a.avg_value}</td>
    <td style="padding: 8px 12px; border-bottom: 1px solid #e5e7eb; text-align: right; color: ${color}; font-weight: 700;">${arrow} ${sign}${a.deviation_pct}%</td>
    <td style="padding: 8px 12px; border-bottom: 1px solid #e5e7eb; text-align: center;"><span style="background: ${color}; color: #fff; padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 700;">${a.severity.toUpperCase()}</span></td>
  </tr>`;
}).join('');

const criticalCount = anomalies.filter(a => a.severity === 'critical').length;
const warningCount = anomalies.filter(a => a.severity === 'warning').length;

const html = `<h3 style="margin: 0 0 8px;">KPI Anomaly Report</h3>
<p style="color: #6b7280; margin: 0 0 16px;">${criticalCount} critical, ${warningCount} warning anomalies detected vs 4-week rolling average</p>
<table style="width: 100%; border-collapse: collapse; font-size: 14px;">
  <thead>
    <tr style="background: #f3f4f6;">
      <th style="padding: 8px 12px; text-align: left;">Metric</th>
      <th style="padding: 8px 12px; text-align: right;">Today</th>
      <th style="padding: 8px 12px; text-align: right;">4wk Avg</th>
      <th style="padding: 8px 12px; text-align: right;">Deviation</th>
      <th style="padding: 8px 12px; text-align: center;">Severity</th>
    </tr>
  </thead>
  <tbody>${rows}</tbody>
</table>`;

const maxSeverity = criticalCount > 0 ? 'critical' : 'warning';
const title = `${anomalies.length} KPI Anomal${anomalies.length === 1 ? 'y' : 'ies'} Detected`;

return [{ json: {
  alert_type: 'kpi_anomaly',
  alert_title: title,
  alert_body: html,
  severity: maxSeverity,
  source_workflow: 'TG-110',
  metadata: { anomalies, timestamp }
} }];

// No anomalies — all KPIs within normal range
return [{ json: {
  status: 'all_normal',
  message: 'All KPIs within 25% of 4-week rolling average',
  timestamp: new Date().toISOString()
} }];
